solution: ```class Solution {
    public int countLargestGroup(int n) {
        int[] freq = new int[37]; // max digit sum for 9999 is 36
        for (int i = 1; i <= n; i++) {
            int sum = 0, x = i;
            while (x > 0) {
                sum += x % 10;
                x /= 10;
            }
            freq[sum]++;
        }
        int max = 0, count = 0;
        for (int v : freq) {
            if (v > max) {
                max = v;
                count = 1;
            } else if (v == max) {
                count++;
            }
        }
        return count;
    }
}
